/* Aurora hosted webfonts
   Install with aurora-tokens when a consumer wants the canonical Aurora typefaces. */

@font-face {
  font-family: "Manrope";
  font-style: normal;
  font-weight: 200 800;
  font-display: swap;
  src: url("https://aurora.tootie.tv/fonts/aurora/manrope-var.woff2") format("woff2-variations");
}

@font-face {
  font-family: "Inter";
  font-style: normal;
  font-weight: 100 900;
  font-display: swap;
  src: url("https://aurora.tootie.tv/fonts/aurora/inter-var.woff2") format("woff2-variations");
}

@font-face {
  font-family: "Noto Sans";
  font-style: normal;
  font-weight: 100 900;
  font-display: swap;
  src: url("https://aurora.tootie.tv/fonts/aurora/noto-sans-var.woff2") format("woff2");
}

@font-face {
  font-family: "JetBrains Mono";
  font-style: normal;
  font-weight: 100 800;
  font-display: swap;
  src: url("https://aurora.tootie.tv/fonts/aurora/jetbrains-mono-var.woff2") format("woff2-variations");
}
